 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Database extends \mysqli { function __construct(string|null $hostname = null, string|null $username = null, string|null $password = null, string|null $database = null, int|null $port = null, string|null $socket = null) { parent::__construct($hostname, $username, $password, $database, $port, $socket); if ($this->connect_errno) { throw new \Exception("The connection to the database has failed!\n{$this->connect_error}"); } } function __destruct() { try { $this->close(); } catch (\Throwable $throwable) { } } } 